module top_module (
    input [2:0] p,
    output reg invalid_z
);

    always @(*) begin
        case (p)
            3'b000: invalid_z = 1;
            3'b001: invalid_z = 1;
            3'b010: invalid_z = 0;
            3'b011: invalid_z = 1;
            3'b100: invalid_z = 1;
            3'b101: invalid_z = 0;
            3'b110: invalid_z = 1;
            3'b111: invalid_z = 0;
            default: invalid_z = 0; // Default case
        endcase
    end
endmodule
